import { Tabs, TabList } from '@/components/molecules/Tabs';
import { PageHeader, PageHeaderProps } from '../PageHeader';
import { PageLayoutCard } from './base/LayoutCard';

export interface TabItem {
  label: string;
  id: string;
}

export interface PageLayoutBaseProps {
  children: React.ReactNode;
  title?: string;
  tabs?: TabItem[];
  selectedTab?: TabItem['id'];
  onTabChange?: (tabId: string) => void;
  variant?: PageHeaderProps['variant'];
  headerActions?: React.ReactNode;
  tabsSize?: 'sm' | 'md';
  withDivider?: boolean;
}
export interface PageLayoutProps
  extends
    PageLayoutBaseProps,
    Omit<React.ComponentProps<'div'>, 'children' | 'title'> {}

export function PageLayout({
  children,
  title,
  tabs,
  selectedTab,
  onTabChange,
  variant = 'primary',
  headerActions,
  tabsSize = 'sm',
  withDivider = undefined,
  className,
  ...rest
}: PageLayoutProps) {
  const handleSelectionChange = (key: React.Key) => {
    const tabTo = key as string;
    onTabChange?.(tabTo);
  };

  return (
    <PageLayoutCard
      rootClassName={className}
      {...rest}
    >
      <PageHeader
        variant={variant}
        className="border-b border-secondary"
        withDivider={withDivider}
      >
        {title ? <PageHeader.Header>{title}</PageHeader.Header> : null}
        {headerActions ? (
          <PageHeader.Actions className="border-b-0 py-1">
            {headerActions}
          </PageHeader.Actions>
        ) : null}
        <PageHeader.Content>
          {tabs && tabs.length > 0 ? (
            <Tabs
              selectedKey={selectedTab}
              onSelectionChange={handleSelectionChange}
            >
              <TabList
                type="underline"
                orientation="horizontal"
                items={tabs}
                size={tabsSize}
                className="before:hidden"
              />
            </Tabs>
          ) : null}
        </PageHeader.Content>
      </PageHeader>
      <div className="flex-1 min-h-0 overflow-y-auto">{children}</div>
    </PageLayoutCard>
  );
}
